            {/* Segmento naranja (Warning) */}
            <circle cx="50" cy="50" r="35" stroke="#f1c40f" strokeWidth="10" fill="none" strokeDasharray="220" strokeDashoffset="60" strokeLinecap="round" />
            {/* Segmento rojo (Down) */}
